      "path": "mini_ai/markov_chain.py",
      "content": "from __future__ import annotations
import random
class MarkovChain:
    def __init__(self, order: int = 1):
        self.order = order
        self.chain: dict[tuple[str], list[str]] = {}

    def train(self, text: str) -> None:
        for i in range(len(text) - self.order):
            state = tuple(text[i:i + self.order])
            next_char = text[i + self.order]
            if state not in self.chain:
                self.chain[state] = []
            self.chain[state].append(next_char)

    def generate(self, length: int, seed: str | None = None, random_seed: int | None = None) -> str:
        if random_seed is not None:
            random.seed(random_seed)
        if seed is not None and len(seed) >= self.order:
            state = tuple(seed[-self.order:])
        else:
            state = random.choice(list(self.chain.keys()))
        result = list(state)
        for _ in range(length - self.order):
            next_char = random.choice(self.chain[state])
            result.append(next_char)
            state = tuple(result[-self.order:])
        return ''.join(result)

    def to_dict(self) -> dict:
        return {'order': self.order, 'chain': self.chain}

    @classmethod
    def from_dict(cls, data: dict) -> MarkovChain:
        instance = cls(order=data['order'])
        instance.chain = data['chain']
        return instance"
